'use client';

import { useEffect, useState, useCallback } from 'react';
import { fetchCollaborators, type Collaborator } from '@/services/collaboration.service';

interface Props {
  workflowId: string;
}

/**
 * CollaboratorAvatars — Figma-style avatar stack in the canvas toolbar.
 * Shows accepted collaborators as overlapping circular avatars.
 */
export default function CollaboratorAvatars({ workflowId }: Props) {
  const [collabs, setCollabs] = useState<Collaborator[]>([]);

  const load = useCallback(async () => {
    try {
      const data = await fetchCollaborators(workflowId);
      setCollabs(data.filter((c) => c.status === 'accepted'));
    } catch {
      // Viewer role cannot list collaborators — silently ignore
    }
  }, [workflowId]);

  useEffect(() => {
    load();
  }, [load]);

  if (collabs.length === 0) return null;

  const visible = collabs.slice(0, 4);
  const overflow = collabs.length - visible.length;

  return (
    <div className="flex items-center -space-x-1.5">
      {visible.map((c, i) => {
        const initial = (c.nickname || c.email || '?')[0].toUpperCase();
        const hue = ((c.user_id.charCodeAt(0) ?? 0) * 37) % 360;
        return (
          <div
            key={c.id}
            className="relative h-5 w-5 rounded-full border-[1.5px] border-background flex items-center justify-center text-[8px] font-semibold text-white shadow-sm transition-transform hover:scale-110 hover:z-10"
            style={{
              backgroundColor: `hsl(${hue}, 55%, 50%)`,
              zIndex: visible.length - i,
            }}
            title={`${c.nickname || c.email} (${c.role === 'editor' ? '编辑' : '查看'})`}
          >
            {initial}
          </div>
        );
      })}
      {overflow > 0 && (
        <div
          className="relative h-5 w-5 rounded-full border-[1.5px] border-background bg-muted flex items-center justify-center text-[8px] font-medium text-muted-foreground shadow-sm"
          style={{ zIndex: 0 }}
          title={`还有 ${overflow} 位协作者`}
        >
          +{overflow}
        </div>
      )}
    </div>
  );
}

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';
import { getConfigs, updateConfig } from '@/services/admin.service';
import type { ConfigEntry } from '@/types/admin';
import { EmptyState, PageHeader } from '@/features/admin/shared';
import { ConfigEditorTable } from './ConfigEditorTable';

export function AdminConfigPageView() {
  const [configs, setConfigs] = useState<ConfigEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [savingKey, setSavingKey] = useState<string | null>(null);
  const [draftValues, setDraftValues] = useState<Record<string, string>>({});
  const [newKey, setNewKey] = useState('');
  const [newValue, setNewValue] = useState('{}');
  const [newDescription, setNewDescription] = useState('');

  const configCountText = useMemo(
    () => (configs.length > 0 ? `当前共 ${configs.length} 项系统配置` : '支持读取、修改和新增系统配置'),
    [configs.length]
  );

  const fetchConfigs = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await getConfigs();
      setConfigs(result.configs);
      setDraftValues(
        Object.fromEntries(
          result.configs.map((entry) => [entry.key, JSON.stringify(entry.value, null, 2)])
        )
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : '加载系统配置失败');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void fetchConfigs();
  }, [fetchConfigs]);

  async function handleSave(entry: ConfigEntry) {
    const confirmed = window.confirm(`确认保存配置 ${entry.key} 吗？`);
    if (!confirmed) return;

    setSavingKey(entry.key);
    try {
      const nextValue = JSON.parse(draftValues[entry.key] ?? 'null');
      await updateConfig(entry.key, nextValue, entry.description);
      await fetchConfigs();
    } catch (err) {
      setError(err instanceof Error ? err.message : '保存配置失败，请确认 JSON 格式正确');
    } finally {
      setSavingKey(null);
    }
  }

  async function handleCreate() {
    if (!newKey.trim()) {
      setError('请填写配置键。');
      return;
    }

    const confirmed = window.confirm(`确认新建配置 ${newKey.trim()} 吗？`);
    if (!confirmed) return;

    setSavingKey(newKey.trim());
    try {
      const parsedValue = JSON.parse(newValue);
      await updateConfig(newKey.trim(), parsedValue, newDescription.trim() || null);
      setNewKey('');
      setNewValue('{}');
      setNewDescription('');
      await fetchConfigs();
    } catch (err) {
      setError(err instanceof Error ? err.message : '新建配置失败，请确认 JSON 格式正确');
    } finally {
      setSavingKey(null);
    }
  }

  return (
    <div className="mx-auto min-h-full max-w-[1600px] space-y-5 px-6 py-6">
      <PageHeader title="系统配置" description={configCountText} />

      {error ? (
        <div className="flex items-center justify-between rounded-md border border-destructive/30 bg-destructive/10 p-4 text-[13px] text-destructive">
          <div className="flex items-center gap-3">
            <span className="material-symbols-outlined text-[20px] text-destructive">error</span>
            <span>{error}</span>
          </div>
          <button 
            onClick={() => void fetchConfigs()} 
            className="flex items-center gap-1 text-[12px] font-medium text-destructive hover:text-destructive transition-colors"
          >
            <span className="material-symbols-outlined text-[16px]">refresh</span>
            重试
          </button>
        </div>
      ) : null}

      <ConfigEditorTable
        configs={configs}
        loading={loading}
        draftValues={draftValues}
        savingKey={savingKey}
        onChangeDraft={(key, value) => setDraftValues((current) => ({ ...current, [key]: value }))}
        onSave={(entry) => {
          void handleSave(entry);
        }}
      />

      <section className="rounded-md border border-border bg-card p-6">
        <div className="flex items-center gap-2 mb-2">
          <span className="material-symbols-outlined text-[20px] text-muted-foreground/60">add_box</span>
          <h2 className="text-[14px] font-semibold text-foreground">新建配置</h2>
        </div>
        <p className="text-[13px] text-muted-foreground mb-6">配置值需填写为合法 JSON，可直接写对象、数组、布尔值或字符串。</p>

        <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
          <input
            value={newKey}
            onChange={(event) => setNewKey(event.target.value)}
            placeholder="配置键，例如 feature.admin.notice"
            className="w-full rounded-md border border-border bg-card px-4 py-2.5 text-[13px] text-foreground transition-all placeholder:text-muted-foreground/60 focus:border-primary focus:outline-none focus:ring-1 focus:ring-ring"
          />
          <input
            value={newDescription}
            onChange={(event) => setNewDescription(event.target.value)}
            placeholder="配置说明"
            className="w-full rounded-md border border-border bg-card px-4 py-2.5 text-[13px] text-foreground transition-all placeholder:text-muted-foreground/60 focus:border-primary focus:outline-none focus:ring-1 focus:ring-ring"
          />
        </div>

        <textarea
          value={newValue}
          onChange={(event) => setNewValue(event.target.value)}
          rows={6}
          className="mt-4 w-full rounded-md border border-border bg-secondary px-4 py-3 font-mono text-[13px] text-muted-foreground transition-all focus:border-primary focus:bg-card focus:outline-none focus:ring-1 focus:ring-ring"
        />

        <div className="mt-6 flex flex-col items-start justify-between gap-6 md:flex-row md:items-center">
          <div className="flex items-start gap-3 rounded-lg bg-amber-950/30 border border-amber-800/40 px-4 py-3 text-[13px] text-amber-400">
            <span className="material-symbols-outlined mt-0.5 text-[18px] text-amber-400">warning</span>
            <p><strong>危险操作提醒</strong>：系统配置变更会直接影响后台行为，保存前请确认键名和值符合预期。</p>
          </div>

          <button
            onClick={() => void handleCreate()}
            disabled={savingKey === newKey.trim()}
            className="flex shrink-0 items-center gap-2 rounded-md bg-primary px-6 py-2.5 text-[13px] font-medium text-primary-foreground transition-all hover:bg-primary/90 disabled:cursor-not-allowed disabled:opacity-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-primary"
          >
            {savingKey === newKey.trim() ? (
              <>
                <span className="material-symbols-outlined animate-spin text-[18px]">progress_activity</span>
                创建中...
              </>
            ) : (
              <>
                <span className="material-symbols-outlined text-[18px]">add</span>
                新建配置
              </>
            )}
          </button>
        </div>
      </section>
    </div>
  );
}

'use client';

import { useMemo, useState } from 'react';
import { motion } from 'framer-motion';
import type { RecentCallsResponse } from '@/types/usage';
import {
  EmptyState,
  Pagination,
  StatusBadge,
  TableSkeletonRows,
  formatDateTime,
  truncateId,
} from '@/features/admin/shared';

interface DashboardActivityTableProps {
  recentCalls: RecentCallsResponse | null;
  loading: boolean;
}

const HEADERS = ['调用 ID', '账本来源', '模型', '状态', 'Tokens', '费用', '开始时间'];
const PAGE_SIZE = 10;

function formatCny(value: number) {
  return new Intl.NumberFormat('zh-CN', {
    style: 'currency',
    currency: 'CNY',
    minimumFractionDigits: value >= 1 ? 2 : 4,
    maximumFractionDigits: value >= 1 ? 2 : 4,
  }).format(value);
}

export function DashboardActivityTable({ recentCalls, loading }: DashboardActivityTableProps) {
  const [page, setPage] = useState(1);

  const allCalls = recentCalls?.calls ?? [];
  const total = allCalls.length;
  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));
  const pagedCalls = useMemo(
    () => allCalls.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE),
    [allCalls, page],
  );

  return (
    <motion.section
      initial={{ opacity: 0, y: 18 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, amount: 0.15 }}
      transition={{ duration: 0.35, ease: 'easeOut' }}
      className="overflow-hidden rounded-md border border-border bg-card"
    >
      <div className="flex items-center justify-between border-b border-border bg-card px-5 py-3.5">
        <div className="flex items-center gap-2.5">
          <span className="material-symbols-outlined text-[18px] text-primary">history</span>
          <h2 className="text-[14px] font-medium text-foreground">最近真实调用</h2>
        </div>
        <span className="text-[11px] text-muted-foreground/60">共 {total} 条</span>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left whitespace-nowrap text-[13px]">
          <thead>
            <tr className="border-b border-border">
              {HEADERS.map((header) => (
                <th key={header} className="px-5 py-2.5 text-[11px] font-medium tracking-wider text-muted-foreground/60 uppercase">
                  {header}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {loading ? (
              <TableSkeletonRows rows={PAGE_SIZE} cols={7} />
            ) : pagedCalls.length === 0 ? (
              <tr>
                <td colSpan={7} className="p-8">
                  <EmptyState title="暂无 AI 调用数据" description="当前时间范围内还没有采集到真实 Provider 调用。" />
                </td>
              </tr>
            ) : (
              pagedCalls.map((call) => (
                <tr key={call.id} className="transition-colors hover:bg-muted">
                  <td className="px-5 py-3 font-mono text-[12px] text-muted-foreground">{truncateId(call.id)}</td>
                  <td className="px-5 py-3">
                    <div className="font-medium text-foreground">
                      {call.source_type}
                      <span className="mx-1 text-muted-foreground/60">/</span>
                      <span className="text-muted-foreground font-normal">{call.source_subtype}</span>
                    </div>
                    {call.is_fallback ? (
                      <span className="mt-0.5 inline-block rounded border border-amber-800/40 bg-amber-950/30 px-1.5 py-0.5 text-[10px] font-medium text-amber-400">
                        FALLBACK
                      </span>
                    ) : null}
                  </td>
                  <td className="px-5 py-3">
                    <div className="font-medium text-foreground">
                      {call.provider}<span className="mx-1 text-muted-foreground/60">/</span>{call.model}
                    </div>
                    <div className="mt-0.5 text-[12px] text-muted-foreground">{call.vendor} · {call.billing_channel}</div>
                  </td>
                  <td className="px-5 py-3">
                    <StatusBadge
                      label={call.status}
                      className={call.status === 'success' ? 'border-accent/30 bg-accent/10 text-accent' : 'border-rose-800/40 bg-rose-950/30 text-rose-400'}
                    />
                  </td>
                  <td className="px-5 py-3 font-mono text-[12px] text-muted-foreground">{call.total_tokens.toLocaleString('zh-CN')}</td>
                  <td className="px-5 py-3 font-medium text-foreground">{formatCny(call.cost_amount_cny)}</td>
                  <td className="px-5 py-3 text-[12px] text-muted-foreground">{formatDateTime(call.started_at)}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <Pagination page={page} totalPages={totalPages} total={total} loading={loading} onPageChange={setPage} />
    </motion.section>
  );
}

