'use client';

import { useEffect, useMemo, useState } from 'react';
import type { NodeConfigFieldSchema, NodeConfigFieldSchemaOption } from '@/types';
import { useWorkflowStore } from '@/stores/workflow/use-workflow-store';
import { useNodeManifest } from '@/features/workflow/hooks/use-node-manifest';
import { authedFetch } from '@/services/api-client';
import { getAgentModels, getAgents, type AgentDirectoryItem, type AgentModelsResponse } from '@/services/agent.service';
import { buildLoopGroupConfigPatch, buildMergedConfigPatch } from './config-patch';
import { NodeConfigField } from './NodeConfigField';
import { KnowledgeNodeLibrary } from './KnowledgeNodeLibrary';
import { resolveNodeConfigCopy } from './resolve-node-config-copy';

interface NodeConfigFormContentProps {
  nodeId: string;
  showExecutionNotice?: boolean;
}

function buildDefaultConfig(schema: NodeConfigFieldSchema[]) {
  return Object.fromEntries(
    schema
      .filter((field) => field.default !== undefined)
      .map((field) => [field.key, field.default]),
  );
}

async function fetchDynamicOptions(
  nodeType: string,
  fieldKey: string,
): Promise<NodeConfigFieldSchemaOption[]> {
  try {
    const res = await authedFetch(`/api/nodes/config-options/${nodeType}/${fieldKey}`);
    if (!res.ok) return [];
    const data = (await res.json()) as { options: NodeConfigFieldSchemaOption[] };
    return data.options ?? [];
  } catch {
    return [];
  }
}

export function NodeConfigFormContent({ nodeId, showExecutionNotice = false }: NodeConfigFormContentProps) {
  const nodes = useWorkflowStore((state) => state.nodes);
  const executionSession = useWorkflowStore((state) => state.executionSession);
  const updateNodeData = useWorkflowStore((state) => state.updateNodeData);
  const { manifest, isLoading, error } = useNodeManifest();

  const node = useMemo(() => nodes.find((item) => item.id === nodeId) ?? null, [nodeId, nodes]);
  const nodeType = String((node?.data as { type?: string } | undefined)?.type ?? node?.type ?? '');
  const nodeLabel = (node?.data as { label?: string } | undefined)?.label;
  const manifestItem = useMemo(
    () => manifest.find((item) => item.type === nodeType) ?? null,
    [manifest, nodeType],
  );
  const existingConfig = useMemo(
    () => ((node?.data as { config?: Record<string, unknown> } | undefined)?.config ?? {}),
    [node?.data],
  );

  const baseConfig = useMemo(() => {
    if (nodeType === 'loop_group') {
      return {
        maxIterations: (node?.data as Record<string, unknown>)?.maxIterations,
        intervalSeconds: (node?.data as Record<string, unknown>)?.intervalSeconds,
        description: (node?.data as Record<string, unknown>)?.description,
      };
    }
    return existingConfig;
  }, [existingConfig, node?.data, nodeType]);

  const baseSchema = useMemo(() => manifestItem?.config_schema ?? [], [manifestItem]);
  const [dynamicSchemaOverlay, setDynamicSchemaOverlay] = useState<NodeConfigFieldSchema[] | null>(null);
  const [agentDirectoryItem, setAgentDirectoryItem] = useState<AgentDirectoryItem | null>(null);
  const [agentModelsInfo, setAgentModelsInfo] = useState<AgentModelsResponse | null>(null);
  const [agentInfoError, setAgentInfoError] = useState<string | null>(null);
  const schema = dynamicSchemaOverlay ?? baseSchema;
  const isAgentNode = manifestItem?.model_source === 'agent' && Boolean(manifestItem?.agent_name);

  useEffect(() => {
    let cancelled = false;

    void (async () => {
      const hasDynamic = baseSchema.some((field) => field.dynamic_options);
      if (!hasDynamic) {
        if (!cancelled) {
          setDynamicSchemaOverlay(null);
        }
        return;
      }

      const resolved = await Promise.all(
        baseSchema.map(async (field) => {
          if (!field.dynamic_options) {
            return field;
          }
          const options = await fetchDynamicOptions(nodeType, field.key);
          return { ...field, options };
        }),
      );

      if (!cancelled) {
        setDynamicSchemaOverlay(resolved);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [baseSchema, nodeType]);

  useEffect(() => {
    if (!isAgentNode || !manifestItem?.agent_name) {
      setAgentDirectoryItem(null);
      setAgentModelsInfo(null);
      setAgentInfoError(null);
      return;
    }

    let cancelled = false;

    void (async () => {
      try {
        const [agents, models] = await Promise.all([
          getAgents(),
          getAgentModels(manifestItem.agent_name),
        ]);
        if (cancelled) {
          return;
        }
        setAgentDirectoryItem(agents.find((item) => item.name === manifestItem.agent_name) ?? null);
        setAgentModelsInfo(models);
        setAgentInfoError(null);
      } catch (error) {
        if (!cancelled) {
          setAgentInfoError(error instanceof Error ? error.message : '加载 Agent 信息失败');
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [isAgentNode, manifestItem?.agent_name]);

  const mergedDefaults = useMemo(
    () => ({ ...buildDefaultConfig(schema), ...baseConfig }),
    [baseConfig, schema],
  );

  const applyConfigPatch = (patch: Record<string, unknown>, replace = false) => {
    if (nodeType === 'loop_group') {
      updateNodeData(nodeId, buildLoopGroupConfigPatch(patch));
      return;
    }

    updateNodeData(nodeId, {
      config: buildMergedConfigPatch(baseConfig ?? {}, patch, replace),
    });
  };

  if (!node) {
    return (
      <div className="rounded-xl border border-border/70 bg-muted/20 px-4 py-4 text-sm text-muted-foreground">
        当前没有可编辑的节点。
      </div>
    );
  }

  const copy = resolveNodeConfigCopy({
    nodeLabel,
    nodeType,
    manifestItem,
  });
  const isExecutionRunning = executionSession?.overallStatus === 'running';

  return (
    <div className="space-y-5">
      {isLoading ? (
        <div className="text-sm text-muted-foreground">正在加载节点能力清单...</div>
      ) : error ? (
        <div className="rounded-lg border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
          {error}
        </div>
      ) : (
        <>
          <section className="space-y-3 rounded-xl border border-border/70 bg-muted/20 p-4">
            <div>
              <h3 className="text-sm font-semibold text-foreground">{copy.title}</h3>
              <p className="mt-1 text-xs text-muted-foreground">{copy.description}</p>
            </div>
            <div className="flex flex-wrap items-center gap-2">
              <span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                能力摘要
              </span>
              {(manifestItem?.output_capabilities ?? []).map((capability) => (
                <span
                  key={capability}
                  className="rounded-full border border-primary/20 bg-primary/5 px-2 py-0.5 text-[11px] text-primary"
                >
                  {capability}
                </span>
              ))}
            </div>
            {manifestItem?.deprecated_surface ? (
              <p className="text-xs text-amber-700 dark:text-amber-300">
                已废弃旧入口：{manifestItem.deprecated_surface}，请以当前节点面板为主。
              </p>
            ) : null}
          </section>

          <section className="space-y-4 rounded-xl border border-border/70 bg-muted/20 p-4">
            {isAgentNode ? (
              <div className="space-y-3 rounded-xl border border-rose-200/70 bg-rose-50/50 p-4 dark:border-rose-900/40 dark:bg-rose-950/10">
                <div>
                  <h3 className="text-sm font-semibold text-foreground">Agent 绑定信息</h3>
                  <p className="mt-1 text-xs text-muted-foreground">
                    这个节点固定绑定到子后端 Agent，不支持切换到其他 Agent，只能选择该 Agent 提供的模型。
                  </p>
                </div>

                <div className="grid gap-2 text-xs text-muted-foreground">
                  <div>绑定 Agent：<span className="font-mono text-foreground">{manifestItem?.agent_name}</span></div>
                  <div>
                    健康状态：
                    <span className={`ml-1 font-medium ${agentModelsInfo?.healthy ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-700 dark:text-amber-300'}`}>
                      {agentModelsInfo?.healthy ? 'healthy' : 'fallback / unavailable'}
                    </span>
                  </div>
                  <div>
                    模型来源：
                    <span className="ml-1 text-foreground">
                      {agentModelsInfo?.source === 'runtime' ? '子 Agent /v1/models' : 'agents.yaml 注册表回退'}
                    </span>
                  </div>
                  <div>
                    Skills：
                    <span className={`ml-1 font-medium ${agentDirectoryItem?.skills_ready ? 'text-emerald-600 dark:text-emerald-400' : 'text-muted-foreground'}`}>
                      {agentDirectoryItem?.skills_ready ? 'ready' : 'not-ready'}
                    </span>
                    <span className="ml-3">MCP：</span>
                    <span className={`ml-1 font-medium ${agentDirectoryItem?.mcp_ready ? 'text-emerald-600 dark:text-emerald-400' : 'text-muted-foreground'}`}>
                      {agentDirectoryItem?.mcp_ready ? 'ready' : 'not-ready'}
                    </span>
                  </div>
                  {agentModelsInfo?.models.length ? (
                    <div>可选模型：<span className="text-foreground">{agentModelsInfo.models.join(' / ')}</span></div>
                  ) : null}
                </div>

                {(agentDirectoryItem?.capabilities ?? manifestItem?.output_capabilities ?? []).length > 0 ? (
                  <div className="flex flex-wrap gap-2">
                    {(agentDirectoryItem?.capabilities ?? manifestItem?.output_capabilities ?? []).map((capability) => (
                      <span
                        key={capability}
                        className="rounded-full border border-rose-300/70 bg-white/80 px-2 py-0.5 text-[11px] text-rose-700 dark:border-rose-800/50 dark:bg-rose-950/30 dark:text-rose-200"
                      >
                        {capability}
                      </span>
                    ))}
                  </div>
                ) : null}

                {agentInfoError ? (
                  <p className="text-xs text-amber-700 dark:text-amber-300">{agentInfoError}</p>
                ) : null}
              </div>
            ) : null}

            <div className="space-y-2">
              <div>
                <h3 className="text-sm font-semibold text-foreground">执行参数</h3>
                <p className="text-xs text-muted-foreground">
                  所有参数都会写入 `node.data.config`，执行时随节点一起发送给后端。
                </p>
              </div>

              {showExecutionNotice && isExecutionRunning ? (
                <div className="rounded-lg border border-amber-300/60 bg-amber-50 px-3 py-2 text-xs leading-5 text-amber-800 dark:border-amber-700/50 dark:bg-amber-950/20 dark:text-amber-300">
                  当前工作流正在运行。这里的修改会即时写入当前节点真实数据，但不会回溯改变已经开始执行的步骤，主要影响后续保存状态与下一次执行。
                </div>
              ) : null}
            </div>

            {schema.length === 0 ? (
              <p className="text-sm text-muted-foreground">这个节点当前没有额外参数。</p>
            ) : (
              <div className="space-y-4">
                {schema.map((field) => (
                  <NodeConfigField
                    key={field.key}
                    field={field}
                    value={mergedDefaults[field.key]}
                    onChange={(value) => {
                      applyConfigPatch({
                        [field.key]: value,
                      });
                    }}
                  />
                ))}
              </div>
            )}

            <div className="flex items-center gap-3">
              <button
                type="button"
                onClick={() => applyConfigPatch(buildDefaultConfig(schema), true)}
                className="rounded-lg border border-border px-4 py-2 text-sm text-foreground transition-colors hover:bg-muted"
              >
                恢复默认
              </button>
            </div>
          </section>

          {nodeType === 'knowledge_base' ? <KnowledgeNodeLibrary /> : null}
        </>
      )}
    </div>
  );
}

'use client';

import { memo, useCallback, useState } from 'react';
import { Handle, Position, type NodeProps } from '@xyflow/react';
import { Settings2 } from 'lucide-react';
import type { AIStepNodeData } from '@/types';
import { getNodeTypeMeta, getNodeTheme } from '@/features/workflow/constants/workflow-meta';
import { getCommunityIcon } from '@/features/community-nodes/constants/catalog';
import { useNodeManifestItem } from '@/features/workflow/hooks/use-node-manifest';
import { useWorkflowStore } from '@/stores/workflow/use-workflow-store';
import { eventBus } from '@/lib/events/event-bus';
import BranchManagerPanel from './BranchManagerPanel';
import { NodeModelSelector } from './NodeModelSelector';
import { NodeInputBadges } from './NodeInputBadges';
import { NodeResultSlip } from './NodeResultSlip';
import { resolveCanvasNodeDescription } from './resolve-canvas-node-description';

type WorkflowNodeVisualData = AIStepNodeData & { hideSlip?: boolean };

function AIStepNode({ data, selected, type, id }: NodeProps) {
  const nodeData = data as unknown as WorkflowNodeVisualData;
  const { error, label, model_route, output, output_format, status, input_snapshot, execution_time_ms } = nodeData;
  const nodeType = nodeData.type ?? type ?? 'chat_response';
  const isLogicSwitch = nodeType === 'logic_switch';
  const isCommunityNode = nodeType === 'community_node';
  const typeMeta = getNodeTypeMeta(nodeType);
  const nodeTheme = getNodeTheme(nodeType);
  const { manifestItem } = useNodeManifestItem(nodeType);
  const HeaderIcon = isCommunityNode
    ? getCommunityIcon(nodeData.community_icon)
    : typeMeta.icon;
  const description = resolveCanvasNodeDescription({
    nodeType,
    isCommunityNode,
    inputHint: nodeData.input_hint,
    manifestItem,
  });
  const shouldShowModelSelector = manifestItem
    ? manifestItem.model_source !== 'none'
    : typeMeta.requiresModel;
  const statusBadge = status === 'running' ? '(ACTIVE)' : status === 'waiting' ? '(WAIT)' : '';

  // Independent Selection Trackers
  const [activePart, setActivePart] = useState<'card' | 'slip'>('card');
  const showAllNodeSlips = useWorkflowStore((s) => s.showAllNodeSlips);
  const hideSlip = nodeData.hideSlip === true;
  const isSlipVisible = showAllNodeSlips && !hideSlip;

  const cardShadow = selected && activePart === 'card' ? 'ring-2 ring-primary/40 shadow-xl shadow-primary/10 scale-[1.02]' : '';

  // Click-to-connect
  const clickConnectState = useWorkflowStore((s) => s.clickConnectState);
  const isWaitingTarget = clickConnectState.phase === 'waiting-target';
  const isSourceOfCurrentConnect = isWaitingTarget && clickConnectState.sourceNodeId === id;

  const handleHandleClick = useCallback(
    (e: React.MouseEvent, handleId: string, handleType: 'source' | 'target') => {
      e.stopPropagation();
      const store = useWorkflowStore.getState();
      const state = store.clickConnectState;

      if (handleType === 'source') {
        if (state.phase === 'idle') {
          store.startClickConnect(id, handleId);
        } else if (state.phase === 'waiting-target' && state.sourceNodeId === id) {
          store.cancelClickConnect();
        } else {
          store.startClickConnect(id, handleId);
        }
      } else {
        if (state.phase === 'waiting-target') {
          store.completeClickConnect(id, handleId);
        }
      }
    },
    [id]
  );

  return (
    <div
      className="relative w-[22rem] transition-all duration-200"
      role="article"
      aria-label={`节点: ${label}`}
    >
      {/* 主卡片 */}
        <div 
          className={`${cardShadow} node-paper-bg relative w-full rounded-md transition-all duration-200 ${nodeTheme.borderClass} p-6 flex flex-col z-20`}
        onClick={() => {
          setActivePart('card');
          // Allow ReactFlow to select the node normally.
        }}
      >
        {/* Target Handles (输入) */}
        <Handle type="target" id="target-left" position={Position.Left}
          className={`node-handle !h-3 !w-3 !-left-[8px] !border-2 !border-background !bg-current z-10 ${nodeTheme.headerTextColor} ${isWaitingTarget && !isSourceOfCurrentConnect ? 'node-handle-click-target' : ''}`}
          onClick={(e) => handleHandleClick(e, 'target-left', 'target')}
        />
        <div className={`absolute inset-1 pointer-events-none z-0 ${nodeTheme.innerBorderClass}`} />

        <div className="relative z-10 flex flex-col">
          {/* Header */}
          <div className="flex items-center justify-between mb-5">
            <div className={`flex items-center gap-2 text-[11px] font-mono tracking-wider uppercase font-bold ${nodeTheme.headerTextColor}`}>
              <HeaderIcon className="h-3.5 w-3.5" />
              #{id.slice(0, 3)}_{nodeTheme.category} {statusBadge}
              {isLogicSwitch && (
                <span className="rounded-sm border border-amber-500/40 bg-amber-500/10 px-1.5 py-0.5 text-[9px] tracking-[0.18em] text-amber-700 dark:text-amber-300">
                  BRANCH
                </span>
              )}
            </div>
            <div className="flex items-center gap-1.5">
              {shouldShowModelSelector && (
                <NodeModelSelector
                  nodeId={id}
                  nodeType={nodeType}
                  currentModel={model_route ?? ''}
                  nodeThemeColor="currentColor"
                  modelSource={manifestItem?.model_source}
                  agentName={manifestItem?.agent_name}
                />
              )}
              <button
                type="button"
                className="rounded-sm border border-black/10 px-1.5 py-1 text-black/45 transition-colors hover:bg-black/5 hover:text-black dark:border-white/10 dark:text-white/45 dark:hover:bg-white/5 dark:hover:text-white"
                title="节点配置"
                onPointerDown={(event) => event.stopPropagation()}
                onClick={(event) => {
                  event.stopPropagation();
                  const rect = event.currentTarget.getBoundingClientRect();
                  eventBus.emit('workflow:open-node-config', {
                    nodeId: id,
                    anchorRect: {
                      top: rect.top,
                      left: rect.left,
                      right: rect.right,
                      bottom: rect.bottom,
                      width: rect.width,
                      height: rect.height,
                    },
                  });
                }}
              >
                <Settings2 className="h-3.5 w-3.5" />
              </button>
            </div>
          </div>

          {/* Title & Desc */}
          <div className="mb-2">
            <h3 className="text-[22px] font-bold font-serif text-black dark:text-white leading-tight tracking-wide mb-2">
              {label}
            </h3>
            <p className="text-[13px] text-black/60 dark:text-white/60 font-serif leading-relaxed line-clamp-2">
              {description}
            </p>
            {isLogicSwitch && (
              <div className="mt-3 inline-flex items-center gap-1 rounded-sm border border-dashed border-amber-500/40 bg-amber-500/5 px-2 py-1 text-[10px] font-mono uppercase tracking-wider text-amber-700 dark:text-amber-300">
                ⑂ 从右侧或底部拖出分支
              </div>
            )}

            <NodeInputBadges nodeType={nodeType} />
          </div>

          {/* Branch manager — logic_switch only, when selected */}
          {isLogicSwitch && selected && (
            <>
              <hr className="border-t-[1px] border-dashed border-black/15 dark:border-white/15 my-4" />
              <BranchManagerPanel nodeId={id} />
            </>
          )}
        </div>

        {/* Source Handle (输出) */}
        <Handle type="source" id="source-right" position={Position.Right}
          className={`node-handle !h-3 !w-3 !-right-[8px] !border-2 !border-background !bg-current z-10 ${nodeTheme.headerTextColor} ${isSourceOfCurrentConnect && clickConnectState.sourceHandleId === 'source-right' ? 'node-handle-click-source-active' : ''}`}
          onClick={(e) => handleHandleClick(e, 'source-right', 'source')}
        />
      </div>

      {/* 底部运行详情 */}
      {isSlipVisible && (
        <NodeResultSlip
          nodeId={id}
          status={status}
          output={output || ''}
          error={error}
          inputSnapshot={input_snapshot}
          nodeType={nodeType}
          outputFormat={output_format}
          executionTimeMs={execution_time_ms}
          isSelected={selected && activePart === 'slip'}
          onFocusSlip={() => setActivePart('slip')}
        />
      )}
    </div>
  );
}

export default memo(AIStepNode);

'use client';

import { memo, useCallback } from 'react';
import { Trash2, Plus } from 'lucide-react';
import { useWorkflowStore } from '@/stores/workflow/use-workflow-store';

interface BranchInfo {
  edgeId: string;
  branch: string;
  targetId: string;
  targetLabel: string;
}

interface Props {
  nodeId: string;
}

/**
 * BranchManagerPanel — inline branch management for logic_switch nodes.
 * Shows list of outgoing branches with rename/delete. Appears when selected.
 *
 * Design: emerald → amber (branch style), inline in AIStepNode footer area.
 */
function BranchManagerPanel({ nodeId }: Props) {
  const edges = useWorkflowStore((s) => s.edges);
  const nodes = useWorkflowStore((s) => s.nodes);

  const branches: BranchInfo[] = edges
    .filter((e) => e.source === nodeId)
    .map((e) => {
      const data = e.data as Record<string, unknown> | undefined;
      const target = nodes.find((n) => n.id === e.target);
      const targetLabel =
        (target?.data as Record<string, unknown>)?.label as string || e.target.slice(0, 6);
      return {
        edgeId: e.id,
        branch: (data?.branch as string) || '默认',
        targetId: e.target,
        targetLabel,
      };
    });

  const handleRenameBranch = useCallback(
    (edgeId: string, newLabel: string) => {
      const store = useWorkflowStore.getState();
      store.takeSnapshot();
      store.setEdges(
        store.edges.map((e) =>
          e.id === edgeId
            ? { ...e, data: { ...(e.data as Record<string, unknown>), branch: newLabel } }
            : e,
        ),
      );
    },
    [],
  );

  const handleDeleteBranch = useCallback(
    (edgeId: string) => {
      const store = useWorkflowStore.getState();
      store.takeSnapshot();
      store.setEdges(store.edges.filter((e) => e.id !== edgeId));
    },
    [],
  );

  if (branches.length === 0) {
    return (
      <div className="text-[10px] font-serif text-amber-700/50 dark:text-amber-300/50 italic mt-1">
        暂无分支 — 从 Handle 拖出连线创建
      </div>
    );
  }

  return (
    <div className="mt-2 space-y-1">
      <div className="text-[9px] font-mono uppercase tracking-[0.15em] text-amber-700/60 dark:text-amber-300/60 font-bold mb-1">
        ⑂ 分支列表 ({branches.length})
      </div>
      {branches.map((b) => (
        <div
          key={b.edgeId}
          className="flex items-center gap-1.5 rounded-sm border border-dashed border-amber-500/20 bg-amber-500/5 px-2 py-1"
        >
          <input
            className="w-10 bg-transparent text-[10px] font-mono font-bold text-amber-700 dark:text-amber-300 outline-none border-b border-transparent focus:border-amber-500/50 transition-colors"
            defaultValue={b.branch}
            onBlur={(e) => {
              const v = e.target.value.trim();
              if (v && v !== b.branch) handleRenameBranch(b.edgeId, v);
            }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') (e.target as HTMLInputElement).blur();
            }}
            onClick={(e) => e.stopPropagation()}
          />
          <span className="text-[9px] text-foreground/40 font-serif truncate flex-1">
            → {b.targetLabel}
          </span>
          <button
            className="p-0.5 text-foreground/30 hover:text-rose-500 transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              handleDeleteBranch(b.edgeId);
            }}
            title="删除此分支"
          >
            <Trash2 size={10} />
          </button>
        </div>
      ))}
    </div>
  );
}

export default memo(BranchManagerPanel);

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useWorkflowStore } from '@/stores/workflow/use-workflow-store';
import { groupModelsByVendor, canAccessModel, type AIModelOption } from '../../constants/ai-models';
import { useWorkflowCatalog } from '../../hooks/use-workflow-catalog';
import { getUser, type UserInfo } from '@/services/auth.service';
import { getAgentModels, type AgentModelsResponse } from '@/services/agent.service';
import type { NodeModelSource } from '@/types';

interface NodeModelSelectorProps {
  nodeId: string;
  nodeType: string;
  currentModel: string;
  nodeThemeColor: string;
  modelSource?: NodeModelSource;
  agentName?: string | null;
}

// 提取清洗文本：去除半角和全角的括号及其后面的文字
const formatModelName = (name: string) => name.replace(/\s*[（(].*?[）)]/g, '').trim();

/**
 * Track B — Workflow Node Model Selector (2-level: Vendor → Model)
 *
 * Uses manual dropdown (useState + useRef) instead of Radix DropdownMenu
 * to avoid ReactFlow event-swallowing and Portal positioning conflicts.
 */
function CatalogNodeModelSelector({
  nodeId,
  currentModel,
}: Pick<NodeModelSelectorProps, 'nodeId' | 'currentModel'>) {
  const updateNodeData = useWorkflowStore((s) => s.updateNodeData);
  const { models, isLoading } = useWorkflowCatalog();
  const [user, setUser] = useState<UserInfo | null>(null);
  const userTier = user?.tier;

  const [open, setOpen] = useState(false);
  const [expandedVendor, setExpandedVendor] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  // 清理延迟定时器
  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  // 安全切换厂商面板：带 150ms 延迟，允许鼠标"走对角线"
  const setVendorSafe = useCallback((vendorName: string | null, immediate = false) => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
    if (immediate) {
      setExpandedVendor(vendorName);
    } else {
      timeoutRef.current = setTimeout(() => {
        setExpandedVendor(vendorName);
      }, 150); // 150ms 足够抵消因为对角线移动而在别人项上短暂掠过的情况
    }
  }, []);

  useEffect(() => {
    getUser().then(setUser).catch(() => null);
  }, []);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    function handleClickOutside(e: MouseEvent) {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false);
        setVendorSafe(null, true);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [open]);

  const vendorGroups = groupModelsByVendor(models);

  const handleSelect = useCallback((model: AIModelOption) => {
    if (!canAccessModel(userTier, model)) return;
    updateNodeData(nodeId, { model_route: model.skuId });
    setOpen(false);
    setVendorSafe(null, true);
  }, [userTier, updateNodeData, nodeId, setVendorSafe]);

  const selectedModelInfo = currentModel
    ? models.find((m) => m.skuId === currentModel || m.model === currentModel)
    : undefined;

  const isUnset = !currentModel || !selectedModelInfo;
  const vendorEntries = Object.entries(vendorGroups);

  return (
    <div className="relative" ref={containerRef}>
      {/* Trigger — stopPropagation prevents ReactFlow drag/select */}
      <button
        type="button"
        className="node-model-selector-trigger group flex items-center gap-1.5 focus:outline-none bg-transparent border-none font-mono text-[9px] uppercase transition-all px-1 py-0.5 rounded hover:bg-black/5 dark:hover:bg-white/5"
        title={isLoading ? '加载模型列表...' : isUnset ? '点击选择 AI 模型' : '切换 AI 模型'}
        disabled={isLoading}
        onPointerDown={(e) => e.stopPropagation()}
        onClick={(e) => {
          e.stopPropagation();
          setOpen((v) => !v);
          if (open) {
            setVendorSafe(null, true);
          }
        }}
      >
        {isLoading ? (
          <span className="w-1.5 h-1.5 rounded-full inline-block animate-pulse bg-stone-400" />
        ) : isUnset ? (
          <>
            <span className="w-1.5 h-1.5 rounded-full border border-dashed border-black/30 dark:border-white/30 inline-block" />
            <span className="opacity-40 italic tracking-wide">选择模型</span>
          </>
        ) : (
          <>
            <span
              className="w-1.5 h-1.5 rounded-full inline-block transition-colors"
              style={{ backgroundColor: selectedModelInfo.brandColor }}
            />
            <span className="opacity-70 group-hover:opacity-100">{formatModelName(selectedModelInfo.displayName)}</span>
          </>
        )}
      </button>

      {/* L1: Vendor list */}
      {open && (
        <div
          className="absolute right-0 top-full z-[9999] mt-1 w-44 rounded-lg node-paper-bg border border-dashed border-black/20 dark:border-white/20 shadow-xl py-1 animate-in fade-in slide-in-from-top-1 duration-150"
          onPointerDown={(e) => e.stopPropagation()}
          onMouseLeave={() => setVendorSafe(null, false)}
        >
          {vendorEntries.map(([vendorName, vendorModels]) => {
            const isExpanded = expandedVendor === vendorName;
            const vendorColor = vendorModels[0]?.brandColor ?? '#4B5563';

            return (
              <div 
                key={vendorName} 
                className="relative"
                onMouseEnter={() => {
                  // 如果已经是我，那么立即清除任何可能的离场倒计时（巩固悬停）；否则走 150ms 延时
                  setVendorSafe(vendorName, isExpanded);
                }}
              >
                <button
                  type="button"
                  className={`w-full flex items-center gap-2 px-2.5 py-1.5 text-left font-mono text-[10px] transition-colors
                    ${isExpanded ? 'bg-black/5 dark:bg-white/10' : 'hover:bg-black/5 dark:hover:bg-white/5'}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    // Optional: click also toggles in case hover is finicky (e.g. touch/tablet)
                    setVendorSafe(isExpanded ? null : vendorName, true);
                  }}
                >
                  <span
                    className="w-1.5 h-1.5 rounded-full shrink-0"
                    style={{ backgroundColor: vendorColor }}
                  />
                  <span className="flex-1 truncate font-semibold opacity-70">{vendorName}</span>
                  <svg
                    className="w-3 h-3 opacity-40 ml-auto"
                    fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7" />
                  </svg>
                </button>

                {/* L2: Model list (Flyout / Cascading menu to the right) */}
                {isExpanded && (
                  // 外层加了 pl-1，打造无形的“悬浮安全桥 (CSS Padding Bridge)”，替代 ml-1 以防止物理脱出
                  <div className="absolute left-full top-0 pl-1 z-[10000]">
                    <div className="min-w-[13rem] rounded-lg node-paper-bg border border-dashed border-black/20 dark:border-white/20 shadow-xl py-1 animate-in fade-in zoom-in-95 duration-100">
                      <div className="px-2.5 py-1.5 text-[9px] font-bold text-black/40 dark:text-white/40 uppercase tracking-widest border-b border-dashed border-black/10 dark:border-white/10 mb-1">
                        {vendorName}
                      </div>
                    {vendorModels.map((model) => {
                      const accessible = canAccessModel(userTier, model);
                      const isActive = model.skuId === currentModel || model.model === currentModel;

                      return (
                        <button
                          key={model.model}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleSelect(model);
                          }}
                          disabled={!accessible}
                          className={`w-full flex items-center gap-2 px-2.5 py-1.5 text-left font-mono text-[10px] transition-colors
                            ${!accessible ? 'opacity-40 cursor-not-allowed' : 'hover:bg-black/5 dark:hover:bg-white/5 cursor-pointer'}
                            ${isActive ? 'bg-black/8 dark:bg-white/10 font-semibold' : ''}`}
                        >
                          <span
                            className="w-1.5 h-1.5 rounded-full shrink-0"
                            style={{ backgroundColor: model.brandColor }}
                          />
                          <span className="flex-1 truncate">{formatModelName(model.displayName)}</span>
                          {model.isPremium && (
                            <span className={`text-[8px] border px-1 rounded-sm shrink-0 ${
                              accessible
                                ? 'border-amber-500/30 text-amber-600 dark:text-amber-400'
                                : 'border-stone-400/30 text-stone-500'
                            }`}>
                              PRO
                            </span>
                          )}
                          {isActive && (
                            <span className="w-1 h-1 rounded-full bg-emerald-500 shrink-0" />
                          )}
                        </button>
                      );
                    })}
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function AgentNodeModelSelector({
  nodeId,
  currentModel,
  agentName,
}: Pick<NodeModelSelectorProps, 'nodeId' | 'currentModel' | 'agentName'>) {
  const updateNodeData = useWorkflowStore((s) => s.updateNodeData);
  const [open, setOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [modelInfo, setModelInfo] = useState<AgentModelsResponse | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!agentName) {
      setIsLoading(false);
      setModelInfo(null);
      return;
    }

    let cancelled = false;
    setIsLoading(true);

    void (async () => {
      try {
        const info = await getAgentModels(agentName);
        if (!cancelled) {
          setModelInfo(info);
        }
      } catch {
        if (!cancelled) {
          setModelInfo({
            agent: agentName,
            healthy: false,
            source: 'registry-fallback',
            models: [],
          });
        }
      } finally {
        if (!cancelled) {
          setIsLoading(false);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [agentName]);

  useEffect(() => {
    if (!open) return;
    function handleClickOutside(e: MouseEvent) {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [open]);

  const models = modelInfo?.models ?? [];
  const selectedModel = currentModel.trim();
  const isUnset = !selectedModel;
  const selectedDisplay = isUnset ? '默认模型' : formatModelName(selectedModel);

  return (
    <div className="relative" ref={containerRef}>
      <button
        type="button"
        className="node-model-selector-trigger group flex items-center gap-1.5 focus:outline-none bg-transparent border-none font-mono text-[9px] uppercase transition-all px-1 py-0.5 rounded hover:bg-black/5 dark:hover:bg-white/5"
        title={isLoading ? '加载 Agent 模型列表...' : `切换 ${agentName ?? 'Agent'} 模型`}
        disabled={isLoading}
        onPointerDown={(e) => e.stopPropagation()}
        onClick={(e) => {
          e.stopPropagation();
          setOpen((v) => !v);
        }}
      >
        {isLoading ? (
          <span className="w-1.5 h-1.5 rounded-full inline-block animate-pulse bg-stone-400" />
        ) : (
          <>
            <span
              className={`w-1.5 h-1.5 rounded-full inline-block transition-colors ${
                modelInfo?.healthy ? 'bg-emerald-500' : 'bg-amber-500'
              }`}
            />
            <span className={`group-hover:opacity-100 ${isUnset ? 'opacity-40 italic tracking-wide' : 'opacity-70'}`}>
              {selectedDisplay}
            </span>
          </>
        )}
      </button>

      {open && (
        <div
          className="absolute right-0 top-full z-[9999] mt-1 w-56 rounded-lg node-paper-bg border border-dashed border-black/20 dark:border-white/20 shadow-xl py-1 animate-in fade-in slide-in-from-top-1 duration-150"
          onPointerDown={(e) => e.stopPropagation()}
        >
          <div className="px-2.5 py-1.5 border-b border-dashed border-black/10 dark:border-white/10 mb-1">
            <div className="flex items-center justify-between gap-2">
              <span className="text-[9px] font-bold uppercase tracking-widest text-black/40 dark:text-white/40">
                {agentName}
              </span>
              <span className={`text-[8px] ${modelInfo?.healthy ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-600 dark:text-amber-300'}`}>
                {modelInfo?.healthy ? 'Healthy' : 'Fallback'}
              </span>
            </div>
            <p className="mt-1 text-[9px] text-black/45 dark:text-white/45">
              {modelInfo?.source === 'runtime' ? '来源: /v1/models' : '来源: 注册表回退'}
            </p>
          </div>

          <button
            type="button"
            onClick={(e) => {
              e.stopPropagation();
              updateNodeData(nodeId, { model_route: '' });
              setOpen(false);
            }}
            className={`w-full flex items-center gap-2 px-2.5 py-1.5 text-left font-mono text-[10px] transition-colors hover:bg-black/5 dark:hover:bg-white/5 ${
              isUnset ? 'bg-black/8 dark:bg-white/10 font-semibold' : ''
            }`}
          >
            <span className="w-1.5 h-1.5 rounded-full shrink-0 bg-slate-400" />
            <span className="flex-1 truncate">默认模型（自动）</span>
            {isUnset && <span className="w-1 h-1 rounded-full bg-emerald-500 shrink-0" />}
          </button>

          {models.map((model) => {
            const isActive = model === selectedModel;
            return (
              <button
                key={model}
                type="button"
                onClick={(e) => {
                  e.stopPropagation();
                  updateNodeData(nodeId, { model_route: model });
                  setOpen(false);
                }}
                className={`w-full flex items-center gap-2 px-2.5 py-1.5 text-left font-mono text-[10px] transition-colors hover:bg-black/5 dark:hover:bg-white/5 ${
                  isActive ? 'bg-black/8 dark:bg-white/10 font-semibold' : ''
                }`}
              >
                <span className="w-1.5 h-1.5 rounded-full shrink-0 bg-rose-500" />
                <span className="flex-1 truncate">{formatModelName(model)}</span>
                {isActive && <span className="w-1 h-1 rounded-full bg-emerald-500 shrink-0" />}
              </button>
            );
          })}

          {!isLoading && models.length === 0 && (
            <p className="px-2.5 py-2 text-[10px] text-black/45 dark:text-white/45">
              当前没有可选模型，将回退到 Agent 默认模型。
            </p>
          )}
        </div>
      )}
    </div>
  );
}

export const NodeModelSelector: React.FC<NodeModelSelectorProps> = ({
  nodeId,
  currentModel,
  modelSource,
  agentName,
}) => {
  if (modelSource === 'none') {
    return null;
  }

  if (modelSource === 'agent' && agentName) {
    return (
      <AgentNodeModelSelector
        nodeId={nodeId}
        currentModel={currentModel}
        agentName={agentName}
      />
    );
  }

  return (
    <CatalogNodeModelSelector
      nodeId={nodeId}
      currentModel={currentModel}
    />
  );
};

