"use client";

/**
 * JsonRenderer — renders formatted JSON output for analyzer/planner nodes.
 * Uses Shiki for syntax-highlighted JSON display.
 */

import React, { useMemo } from "react";
import type { NodeRendererProps } from "../index";

export const JsonRenderer: React.FC<NodeRendererProps> = ({
    output,
    isStreaming,
    compact = false,
}) => {
    const formattedJson = useMemo(() => {
        if (!output) return "";
        try {
            const parsed = JSON.parse(output);
            return JSON.stringify(parsed, null, 2);
        } catch {
            return output; // Return raw if not valid JSON yet (streaming)
        }
    }, [output]);

    const summaryText = useMemo(() => {
        if (!output) return "";
        try {
            const parsed = JSON.parse(output) as Record<string, unknown> | unknown[];
            if (Array.isArray(parsed)) {
                return `数组 ${parsed.length} 项`;
            }
            return Object.entries(parsed)
                .slice(0, 3)
                .map(([key, value]) => {
                    if (typeof value === 'string') return `${key}: ${value.slice(0, 20)}${value.length > 20 ? '…' : ''}`;
                    if (Array.isArray(value)) return `${key}: ${value.length}项`;
                    if (value && typeof value === 'object') return `${key}: 对象`;
                    return `${key}: ${String(value)}`;
                })
                .join(' · ');
        } catch {
            const compactText = output.replace(/\s+/g, ' ').trim();
            return compactText.slice(0, 120);
        }
    }, [output]);

    if (!output) {
        return (
            <div className="text-gray-400 text-sm italic">
                {isStreaming ? "分析中..." : "等待执行"}
            </div>
        );
    }

    if (compact) {
        return <div className="text-xs leading-5 text-gray-700">{summaryText}</div>;
    }

    return (
        <pre className="bg-gray-900 text-green-300 p-4 rounded-lg text-xs overflow-x-auto max-h-64 scrollbar-thin">
            <code>{formattedJson}</code>
        </pre>
    );
};

'use client';

import { useState, useCallback, useEffect, useRef } from 'react';
import { X, ChevronUp, ChevronDown } from 'lucide-react';
import { useWorkflowStore } from '@/stores/workflow/use-workflow-store';
import type { AIStepNodeData } from '@/types';
import { eventBus } from '@/lib/events/event-bus';

interface SearchBarProps {
  onClose: () => void;
}

/**
 * Small search bar that pops above the toolbar.
 * Highlights matching nodes by name, Enter cycles through results.
 * Supports Ctrl+P shortcut to open.
 */
export default function SearchBar({ onClose }: SearchBarProps) {
  const [query, setQuery] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const nodes = useWorkflowStore((s) => s.nodes);
  const setSelectedNodeId = useWorkflowStore((s) => s.setSelectedNodeId);

  // Find matching nodes
  const matchingNodes = query.trim()
    ? nodes.filter((n) => {
        const data = n.data as unknown as AIStepNodeData;
        const label = data?.label ?? '';
        return label.toLowerCase().includes(query.toLowerCase());
      })
    : [];

  const totalMatches = matchingNodes.length;

  // Focus input on mount
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  // Highlight and navigate to matched node
  useEffect(() => {
    if (totalMatches > 0 && matchingNodes[currentIndex]) {
      const node = matchingNodes[currentIndex];
      setSelectedNodeId(node.id);

      // Dispatch event to center the canvas on this node
      eventBus.emit('canvas:focus-node', { nodeId: node.id });
    }
  }, [currentIndex, totalMatches, matchingNodes, setSelectedNodeId]);

  const goNext = useCallback(() => {
    if (totalMatches > 0) {
      setCurrentIndex((prev) => (prev + 1) % totalMatches);
    }
  }, [totalMatches]);

  const goPrev = useCallback(() => {
    if (totalMatches > 0) {
      setCurrentIndex((prev) => (prev - 1 + totalMatches) % totalMatches);
    }
  }, [totalMatches]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        if (e.shiftKey) {
          goPrev();
        } else {
          goNext();
        }
      }
      if (e.key === 'Escape') {
        onClose();
      }
    },
    [goNext, goPrev, onClose]
  );

  // Reset index when query changes
  useEffect(() => {
    setCurrentIndex(0);
  }, [query]);

  return (
    <div className="canvas-search-bar">
      <input
        ref={inputRef}
        type="text"
        className="canvas-search-input"
        placeholder="搜索节点名称..."
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        onKeyDown={handleKeyDown}
      />

      {query.trim() && (
        <span className="canvas-search-count">
          {totalMatches > 0 ? `${currentIndex + 1}/${totalMatches}` : '0 结果'}
        </span>
      )}

      <button
        type="button"
        className="canvas-search-nav"
        onClick={goPrev}
        disabled={totalMatches === 0}
        title="上一个 (Shift+Enter)"
      >
        <ChevronUp className="h-3.5 w-3.5" />
      </button>

      <button
        type="button"
        className="canvas-search-nav"
        onClick={goNext}
        disabled={totalMatches === 0}
        title="下一个 (Enter)"
      >
        <ChevronDown className="h-3.5 w-3.5" />
      </button>

      <button
        type="button"
        className="canvas-search-close"
        onClick={onClose}
        title="关闭 (Esc)"
      >
        <X className="h-3.5 w-3.5" />
      </button>
    </div>
  );
}

