'use client';

import { useState, useEffect } from 'react';
import { getUserAiModelCatalog } from '@/services/ai-catalog.service';
import { FALLBACK_AI_MODEL_OPTIONS, type AIModelOption } from '../constants/ai-models';
import { getUser } from '@/services/auth.service';

interface CacheEntry {
  userId: string;
  tier: string;
  models: AIModelOption[];
}

// Module-level cache keyed by user identity (userId + tier).
// Invalidated automatically when these change to prevent cross-session pollution.
let _cache: CacheEntry | null = null;
// Global in-flight promise: prevents N nodes from triggering N parallel API calls.
let _inflight: Promise<AIModelOption[]> | null = null;

/**
 * Fetches the full visible AI model catalog from `/api/ai/models/catalog`.
 *
 * IMPORTANT: The catalog now returns ALL visible models regardless of user tier.
 * Tier-based access control is handled at the UI layer (greyed-out PRO badge)
 * and enforced at the execution layer (403 on unauthorized model use).
 *
 * Cache strategy:
 * - Hit:  same userId + tier → reuse cached models instantly.
 * - Miss: different user, different tier, or cold start → fetch fresh.
 * - Error: degraded to FALLBACK_AI_MODEL_OPTIONS (static list).
 *
 * Bug fixed:
 * - setIsLoading(false) was only called inside `finally { if (!cancelled) ... }`.
 *   When a component unmounts (cancelled=true) before the promise resolves,
 *   any re-mount would restart with isLoading=true but didInit.current=true
 *   (module cache), so setIsLoading(false) was never called → stuck loading.
 * - N workflow nodes mounting simultaneously triggered N parallel fetches,
 *   each with its own 401 → tryRestoreSession → possible redirectToLogin.
 *   Fixed by a module-level _inflight promise dedup.
 */
export function useWorkflowCatalog() {
  const [models, setModels] = useState<AIModelOption[]>(_cache?.models ?? []);
  // Start isLoading=false immediately if module-level cache is already populated.
  const [isLoading, setIsLoading] = useState<boolean>(!_cache);

  useEffect(() => {
    // Fast path: cache already filled (from a previous node mount this session)
    if (_cache) {
      setModels(_cache.models);
      setIsLoading(false);
      return;
    }

    let cancelled = false;

    async function init() {
      try {
        // Identify user for cache keying — never throws (401 caught to null)
        const user = await getUser().catch(() => null);
        if (cancelled) return;

        const userId = user?.id ?? 'anonymous';
        const tier = (user as Record<string, string> | null)?.tier ?? 'free';

        // Re-check cache after awaiting getUser (another node may have filled it)
        if (_cache && _cache.userId === userId && _cache.tier === tier) {
          if (!cancelled) { setModels(_cache.models); setIsLoading(false); }
          return;
        }

        // Deduplicate parallel fetches: reuse in-flight promise if one already exists
        if (!_inflight) {
          _inflight = getUserAiModelCatalog().finally(() => { _inflight = null; });
        }
        const all = await _inflight;
        if (cancelled) return;

        const selectable = all.filter((m) => m.isEnabled && m.isUserSelectable);
        const result = selectable.length > 0 ? selectable : FALLBACK_AI_MODEL_OPTIONS;
        _cache = { userId, tier, models: result };
        setModels(result);
        setIsLoading(false);
      } catch {
        if (!cancelled) {
          // Degraded mode: static fallback — never leave the node with a broken selector
          const degraded = _cache?.models ?? FALLBACK_AI_MODEL_OPTIONS;
          setModels(degraded);
          setIsLoading(false);
        }
      }
    }

    void init();
    return () => { cancelled = true; };
  }, []);

  return { models, isLoading };
}

/**
 * Invalidate the module-level catalog cache.
 * Call this after user tier upgrades, logout, or admin catalog changes.
 */
export function invalidateWorkflowCatalogCache() {
  _cache = null;
  _inflight = null;
}

import { useCallback, useState } from 'react';
import { useRouter } from 'next/navigation';
import { toast } from 'sonner';
import {
  deleteWorkflow,
  renameWorkflow,
} from '@/services/workflow.service';

interface UseWorkflowSidebarActionsResult {
  processingWorkflowId: string | null;
  onRenameWorkflow: (workflowId: string, currentName: string) => Promise<void>;
  onDeleteWorkflow: (workflowId: string, currentName: string) => Promise<void>;
}

export function useWorkflowSidebarActions(
  pathname: string,
  closeContextMenu: () => void
): UseWorkflowSidebarActionsResult {
  const router = useRouter();
  const [processingWorkflowId, setProcessingWorkflowId] = useState<string | null>(
    null
  );

  const onRenameWorkflow = useCallback(
    async (workflowId: string, nextName: string) => {
      closeContextMenu();

      const normalizedName = nextName.trim();
      if (!normalizedName) {
        toast.error('名称不能为空');
        return;
      }

      setProcessingWorkflowId(workflowId);
      try {
        await renameWorkflow(workflowId, normalizedName);
        toast.success('工作流已重命名');
        router.refresh();
      } catch (error) {
        const message =
          error instanceof Error ? error.message : '重命名工作流失败';
        toast.error(message);
      } finally {
        setProcessingWorkflowId(null);
      }
    },
    [closeContextMenu, router]
  );

  const onDeleteWorkflow = useCallback(
    async (workflowId: string, _currentName: string) => {
      setProcessingWorkflowId(workflowId);
      try {
        await deleteWorkflow(workflowId);
        if (pathname === `/c/${workflowId}`) {
          router.push('/workspace');
        }
        router.refresh();
        toast.success('工作流已删除');
      } catch (error) {
        const message =
          error instanceof Error ? error.message : '删除工作流失败';
        toast.error(message);
      } finally {
        setProcessingWorkflowId(null);
      }
    },
    [pathname, router]
  );

  return {
    processingWorkflowId,
    onRenameWorkflow,
    onDeleteWorkflow,
  };
}

import path from 'path';
import fs from 'fs';

/** 文档元数据 */
export interface DocMeta {
  slug: string;
  title: string;
  description?: string;
  lastUpdated?: string;
}

/** 导航项 */
export interface NavItem {
  title: string;
  slug?: string;
  order: number;
  children?: NavItem[];
}

/** TOC 标题项 */
export interface TOCItem {
  id: string;
  title: string;
  level: 2 | 3;
}

/** _meta.json 结构 */
interface MetaItem {
  title: string;
  order?: number;
}

type MetaConfig = Record<string, MetaItem>;

const WIKI_CONTENT_PATH = path.join(process.cwd(), '..', 'docs', 'wiki-content');

/**
 * 读取指定文档内容 + frontmatter
 * @param slug - 如 "getting-started/quick-start"
 * @returns markdown 原文 + frontmatter
 */
export async function getDocContent(slug: string): Promise<{
  content: string;
  frontmatter: DocMeta;
}> {
  const filePath = path.join(WIKI_CONTENT_PATH, `${slug}.md`);
  const fileContent = fs.readFileSync(filePath, 'utf-8');

  // 解析 frontmatter
  const frontmatterMatch = fileContent.match(/^---\n([\s\S]*?)\n---\n/);
  let frontmatter: Partial<DocMeta> = {};
  let content = fileContent;

  if (frontmatterMatch) {
    const yamlContent = frontmatterMatch[1];
    content = fileContent.slice(frontmatterMatch[0].length);

    // 简单 YAML 解析
    yamlContent.split('\n').forEach((line) => {
      const match = line.match(/^([\w-]+):\s*["']?(.*?)["']?\s*$/);
      if (match) {
        const [, key, value] = match;
        if (key === 'title') frontmatter.title = value;
        if (key === 'description') frontmatter.description = value;
        if (key === 'lastUpdated') frontmatter.lastUpdated = value;
      }
    });
  }

  // 如果没有 frontmatter title，从第一个 h1 提取
  if (!frontmatter.title) {
    const h1Match = content.match(/^#\s+(.+)$/m);
    frontmatter.title = h1Match?.[1] || slug.split('/').pop() || 'Untitled';
  }

  return {
    content,
    frontmatter: {
      slug,
      title: frontmatter.title,
      description: frontmatter.description,
      lastUpdated: frontmatter.lastUpdated,
    },
  };
}

/**
 * 扫描所有 .md 文件，返回 slug 列表
 * 用于 generateStaticParams()
 */
export function getAllDocSlugs(): { slug: string[] }[] {
  const slugs: { slug: string[] }[] = [];

  function scanDir(dirPath: string, baseSlug: string[] = []) {
    const items = fs.readdirSync(dirPath, { withFileTypes: true });

    for (const item of items) {
      if (item.name.startsWith('_')) continue; // 跳过 _meta.json 等

      const fullPath = path.join(dirPath, item.name);
      const itemSlug = [...baseSlug, item.name.replace(/\.md$/, '')];

      if (item.isDirectory()) {
        scanDir(fullPath, itemSlug);
      } else if (item.name.endsWith('.md')) {
        slugs.push({ slug: itemSlug });
      }
    }
  }

  if (fs.existsSync(WIKI_CONTENT_PATH)) {
    scanDir(WIKI_CONTENT_PATH);
  }

  return slugs;
}

/**
 * 读取所有 _meta.json，构建完整的导航树
 */
export function getNavigation(): NavItem[] {
  const navItems: NavItem[] = [];

  function readMeta(dirPath: string): MetaConfig | null {
    const metaPath = path.join(dirPath, '_meta.json');
    try {
      const content = fs.readFileSync(metaPath, 'utf-8');
      return JSON.parse(content) as MetaConfig;
    } catch {
      return null;
    }
  }

  function buildNav(dirPath: string, baseSlug: string[] = []): NavItem[] {
    const items: NavItem[] = [];
    const meta = readMeta(dirPath);

    const dirItems = fs.readdirSync(dirPath, { withFileTypes: true });

    // 按 meta order 排序，无 meta 的按字母序
    const sortedItems = dirItems
      .filter((item) => !item.name.startsWith('_') && !item.name.startsWith('.'))
      .sort((a, b) => {
        const aKey = a.name.replace(/\.md$/, '');
        const bKey = b.name.replace(/\.md$/, '');
        const aOrder = meta?.[aKey]?.order ?? Number.MAX_SAFE_INTEGER;
        const bOrder = meta?.[bKey]?.order ?? Number.MAX_SAFE_INTEGER;
        return aOrder - bOrder;
      });

    for (const item of sortedItems) {
      const itemSlug = [...baseSlug, item.name.replace(/\.md$/, '')];
      const key = item.name.replace(/\.md$/, '');
      const metaItem = meta?.[key];

      if (item.isDirectory()) {
        const children = buildNav(path.join(dirPath, item.name), itemSlug);
        if (children.length > 0 || metaItem) {
          items.push({
            title: metaItem?.title || key,
            order: metaItem?.order ?? Number.MAX_SAFE_INTEGER,
            children,
          });
        }
      } else if (item.name.endsWith('.md')) {
        items.push({
          title: metaItem?.title || key,
          slug: itemSlug.join('/'),
          order: metaItem?.order ?? Number.MAX_SAFE_INTEGER,
        });
      }
    }

    return items;
  }

  if (fs.existsSync(WIKI_CONTENT_PATH)) {
    return buildNav(WIKI_CONTENT_PATH);
  }

  return navItems;
}

/**
 * 从 markdown 内容中提取标题，生成 TOC
 */
export function parseTableOfContents(markdown: string): TOCItem[] {
  const toc: TOCItem[] = [];
  const lines = markdown.split('\n');

  for (const line of lines) {
    const match = line.match(/^(#{2,3})\s+(.+)$/);
    if (match) {
      const level = match[1].length as 2 | 3;
      const title = match[2].trim();
      const id = title
        .toLowerCase()
        .replace(/[^\w\s-]/g, '')
        .replace(/\s+/g, '-');

      toc.push({ id, title, level });
    }
  }

  return toc;
}
